function Follow() {
    return(
        <div>
            <section className="hero-v2">
                <h1>Stay Connected.</h1>
                <h2>Follow our Social Media page to keep up with the latest updates and exciting promos!
                </h2>

                <ul>
                    <li><a href="https://www.facebook.com/homeseek">Facebook</a></li>
                    <li><a href="https://www.twitter.com/homeseek">Twitter</a></li>
                    <li><a href="https://www.instagram.com/homeseek">Instagram</a></li>
                </ul>

                <p>Coming soon.</p>
                
            
            </section>
           </div>
    );
}

export default Follow;
